	@Test
	void evaluationCaseSnapshotsBindingsAndDataset() {
		IRI graph = VF.createIRI("urn:test:graph");
		SimpleDataset dataset = new SimpleDataset();
		dataset.addDefaultGraph(graph);
		MapBindingSet bindings = new MapBindingSet();
		bindings.setBinding("x", X);
		EvaluationCase evaluationCase = EvaluationCase.builder("snapshot")
				.dataset(dataset)
				.initialBindings(bindings)
				.build();

		dataset.clear();
		dataset.addNamedGraph(VF.createIRI("urn:test:other"));
		bindings.setBinding("x", VF.createIRI("urn:test:mutated"));
		bindings.setBinding("y", VF.createLiteral("added"));

		assertEquals(Set.of(graph), evaluationCase.getDataset().getDefaultGraphs());
		assertTrue(evaluationCase.getDataset().getNamedGraphs().isEmpty());
		assertEquals(X, evaluationCase.getInitialBindings().getValue("x"));
		assertFalse(evaluationCase.getInitialBindings().hasBinding("y"));
	}

	@Test
	void verifiedRewriteSnapshotsCallerOwnedPlans() {
		StatementPattern before = pattern("s", P1, "o");
		Join proposed = new Join(before.clone(), new SingletonSet());
		TupleExpr expectedBefore = before.clone();
		TupleExpr expectedAfter = proposed.clone();

		VerifiedRewrite verified = new VerifiedRewriteEngine(new AlgebraEquivalenceChecker()).verify(before, proposed);
		assertTrue(verified.accepted(), () -> verified.result().getReason());

		before.replaceChildNode(before.getSubjectVar(), Var.of("mutated"));
		proposed.setLeftArg(new EmptySet());
		assertEquals(expectedBefore, verified.before());
		assertEquals(expectedAfter, verified.after());

		TupleExpr exposed = verified.before();
		assertNotSame(exposed, verified.before());
		StatementPattern exposedPattern = (StatementPattern) exposed;
		exposedPattern.replaceChildNode(exposedPattern.getObjectVar(), Var.of("mutated-again"));
		assertEquals(expectedBefore, verified.before());
	}

	@Test
	void normalizationProofKeepsOnlyTheSelectedFilterPushPath() {
		TupleExpr a = pattern("s", P1, "a");
		TupleExpr b = pattern("s", P2, "b");
		Bound condition = new Bound(Var.of("incoming"));
		TupleExpr original = new Filter(new Join(a.clone(), b.clone()), condition.clone());
		TupleExpr pushedLeft = new Join(new Filter(a.clone(), condition.clone()), b.clone());
		TupleExpr pushedRight = new Join(a.clone(), new Filter(b.clone(), condition.clone()));
		AlgebraEquivalenceChecker checker = new AlgebraEquivalenceChecker(
				CheckOptions.builder().boundedCounterexampleSearch(false).build());

		EquivalenceResult leftResult = checker.check(original, pushedLeft);
		EquivalenceResult rightResult = checker.check(original, pushedRight);
		assertEquals(EquivalenceStatus.UNKNOWN, leftResult.getStatus(), leftResult::getReason);
		assertEquals(EquivalenceStatus.UNKNOWN, rightResult.getStatus(), rightResult::getReason);
	}

