	@Test
	void columnPermutedValuesUnderSliceDoNotTripTheProofKernel() {
		// Equal rows built with different column insertion order: the binding sets are equal, but a
		// row's toString() is iteration-order-sensitive, so the opaque diagnostic encoding must not
		// be derived from it.
		BindingSetAssignment permutedColumns = new BindingSetAssignment();
		permutedColumns.setBindingNames(Set.of("a", "b"));
		permutedColumns.setBindingSets(List.of(
				new ListBindingSet(List.of("b", "a"), VF.createLiteral(2), VF.createLiteral(1))));
		BindingSetAssignment declaredColumns = new BindingSetAssignment();
		declaredColumns.setBindingNames(Set.of("a", "b"));
		declaredColumns.setBindingSets(List.of(
				new ListBindingSet(List.of("a", "b"), VF.createLiteral(1), VF.createLiteral(2))));
		// The Slice forces SEQUENCE mode below it, making the VALUES opaque; the commuted inner
		// union forces the trees through normalization instead of the exact-equality short-circuit.
		TupleExpr original = new Union(
				new Union(pattern("s", P1, "o"), pattern("s", P2, "o")),
				new Slice(permutedColumns, 0, 1));
		TupleExpr candidate = new Union(
				new Union(pattern("s", P2, "o"), pattern("s", P1, "o")),
				new Slice(declaredColumns, 0, 1));

		EquivalenceResult result = assertDoesNotThrow(
				() -> runtimeCheckerWithEmptyCase().check(original, candidate));

		assertEquals(EquivalenceStatus.UNKNOWN, result.getStatus(), result::getReason);
	}

	@Test
	void filterPushIntoLeftJoinKeepsTheScopeBoundary() {
		// Trees differing ONLY in the LeftJoin's variableScopeChange flag must not canonicalize
		// identically: the flag decides whether incoming bindings flow into the OPTIONAL, and the
		// filter push-down used to erase it.
		EquivalenceResult result = runtimeCheckerWithEmptyCase().check(
				filteredLeftJoin(true),
				filteredLeftJoin(false));

		assertNotEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
	}

	private static Filter filteredLeftJoin(boolean scopeBoundary) {
		LeftJoin leftJoin = new LeftJoin(pattern("a", P1, "x"), pattern("a", P2, "c"));
		leftJoin.setVariableScopeChange(scopeBoundary);
		return new Filter(leftJoin, new Compare(
				Var.of("x"),
				new ValueConstant(VF.createLiteral(5)),
				Compare.CompareOp.GT));
	}

	@Test
	void languageTagCaseDeduplicationNeedsAnExplicitCertifiedRule() {
		// RDF4J literal equality compares language tags case-insensitively. The producer can normalize
		// these rows, but the root-only kernel must stay incomplete until that VALUES law has a theorem.
		BindingSetAssignment mixedCase = new BindingSetAssignment();
		mixedCase.setBindingNames(Set.of("x"));
		mixedCase.setBindingSets(List.of(
				new ListBindingSet(List.of("x"), VF.createLiteral("a", "en")),
				new ListBindingSet(List.of("x"), VF.createLiteral("a", "EN"))));
		BindingSetAssignment lowerCase = new BindingSetAssignment();
		lowerCase.setBindingNames(Set.of("x"));
		lowerCase.setBindingSets(List.of(
				new ListBindingSet(List.of("x"), VF.createLiteral("a", "en"))));
		CheckOptions options = CheckOptions.builder()
				.observationMode(ObservationMode.SET)
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(EvaluationCase.builder("empty dataset").build())
				.build();

		EquivalenceResult result = new AlgebraEquivalenceChecker(options).check(mixedCase, lowerCase);

		assertEquals(EquivalenceStatus.UNKNOWN, result.getStatus(), result::getReason);
	}

	@Test
	void unsetValuesRowsCanonicalizeWithoutCrashing() {
		// new BindingSetAssignment() with declared names but no rows is API-legal bean state that
		// the analyzers already null-guard; canonicalization must not crash on it either.
		BindingSetAssignment unset = new BindingSetAssignment();
		unset.setBindingNames(Set.of("x"));

		assertDoesNotThrow(unset::getSignature);
		EquivalenceResult result = assertDoesNotThrow(
				() -> runtimeCheckerWithEmptyCase().check(unset, pattern("s", P1, "o")));

		assertNotEquals(EquivalenceStatus.EQUIVALENT, result.getStatus(), result::getReason);
	}

	private static AlgebraEquivalenceChecker runtimeCheckerWithEmptyCase() {
		CheckOptions options = CheckOptions.builder()
				.boundedCounterexampleSearch(false)
				.addEvaluationCase(EvaluationCase.builder("empty dataset").build())
				.build();
		return new AlgebraEquivalenceChecker(options);
	}

	private static BindingSetAssignment values(String name, Value value) {
		MapBindingSet row = new MapBindingSet();
		row.setBinding(name, value);
		return values(Set.of(name), row);
	}

	private static BindingSetAssignment values(Set<String> declaredNames, MapBindingSet row) {
		BindingSetAssignment assignment = new BindingSetAssignment();
		assignment.setBindingNames(declaredNames);
		assignment.setBindingSets(List.of(row));
		return assignment;
	}

	private static StatementPattern pattern(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(
				Var.of(subjectName),
				Var.of("const-" + predicate.stringValue(), predicate),
				Var.of(objectName));
	}
